from collections import Counter
import heapq

def rearrangeBarcodes(barcodes):
    cnt = Counter(barcodes)
    heap = [(-freq, val) for val, freq in cnt.items()]
    heapq.heapify(heap)
    res = []
    while heap:
        f1, v1 = heapq.heappop(heap)
        res.append(v1)
        if heap:
            f2, v2 = heapq.heappop(heap)
            res.append(v2)
            if f2 + 1: heapq.heappush(heap, (f2+1, v2))
        if f1 + 1: heapq.heappush(heap, (f1+1, v1))
    return res

